import fs from 'fs';
import { execFileSync } from 'child_process';

const src = 'config/permission-matrix.json';
const cfg = JSON.parse(fs.readFileSync(src, 'utf8'));
const banner =
  '// AUTO-GENERATED by scripts/generate-permission-matrix.mjs. Do not edit manually.\n';

const json = JSON.stringify(cfg.roles, null, 2);
const typeFile = `${banner}export type PermissionAction = ${cfg.actions.map(a => `'${a}'`).join(' | ')};\nexport type PermissionResource = ${cfg.resources.map(r => `'${r}'`).join(' | ')};\nexport type PermissionRole = ${Object.keys(
  cfg.roles,
)
  .map(r => `'${r}'`)
  .join(
    ' | ',
  )};\nexport type PermissionRule = Record<PermissionAction, boolean>;\nexport type PermissionMatrix = Record<PermissionRole, Partial<Record<PermissionResource | '*', PermissionRule>>>;\nexport const PERMISSION_MATRIX: PermissionMatrix = ${json} as const;\n`;

const generatedTypeFiles = [
  'src/types/permissionMatrix.generated.ts',
  'supabase/functions/_shared/permissionMatrix.generated.ts',
];
for (const generatedTypeFile of generatedTypeFiles) {
  fs.writeFileSync(generatedTypeFile, typeFile);
}
execFileSync('npx', ['prettier', '--write', ...generatedTypeFiles], { stdio: 'ignore' });

function allowedActions(rule) {
  return cfg.actions.filter(action => rule?.[action] === true).map(a => `'${a}'`);
}

function generateRoleCase(role, resources) {
  const lines = [];
  lines.push(`    WHEN '${role}' THEN`);
  lines.push('      CASE p_resource');

  for (const resource of cfg.resources) {
    const rule = resources[resource] ?? resources['*'];
    if (!rule) {
      lines.push(`        WHEN '${resource}' THEN RETURN FALSE;`);
      continue;
    }
    const allowed = allowedActions(rule);
    if (allowed.length === 0) {
      lines.push(`        WHEN '${resource}' THEN RETURN FALSE;`);
    } else {
      lines.push(`        WHEN '${resource}' THEN RETURN p_action IN (${allowed.join(', ')});`);
    }
  }

  lines.push('        ELSE RETURN FALSE;');
  lines.push('      END');
  return lines.join('\n');
}

const roleCases = Object.entries(cfg.roles)
  .map(([role, resources]) => generateRoleCase(role, resources))
  .join('\n');

const sqlFile = `-- AUTO-GENERATED by scripts/generate-permission-matrix.mjs. Do not edit manually.
CREATE OR REPLACE FUNCTION public.permission_matrix_allows(
  p_role TEXT,
  p_resource TEXT,
  p_action TEXT
)
RETURNS BOOLEAN
LANGUAGE plpgsql
IMMUTABLE
SET search_path = public
AS $$
BEGIN
  CASE p_role
${roleCases}
    ELSE RETURN FALSE;
  END CASE;
END;
$$;
`;

fs.mkdirSync('supabase/sql', { recursive: true });
fs.writeFileSync('supabase/sql/permission_matrix_allows.generated.sql', sqlFile);
console.log('generated permission matrix types + SQL');
